t.script:
(function() {
    function setFilterTop() {
        var hdr  = document.querySelector('header#top, .o_header_standard, nav.navbar');
        var h    = hdr ? hdr.offsetHeight : 0;
        var cat  = document.querySelector('.rms-cat-mobile');
        var diet = document.querySelector('.rms-diet-bar');
        if (cat)  cat.style.top  = h + 'px';
        if (diet) diet.style.top = (h + (cat ? cat.offsetHeight : 0)) + 'px';
    }
    window.addEventListener('load',   setFilterTop);
    window.addEventListener('resize', setFilterTop);
    setFilterTop();
})();

(function() {

    // ---------------------------------------------- //
    // Live search — filters by visible dish name,   //
    // works alongside the existing dietary filter   //
    // (a card only shows if BOTH match).            //
    // ---------------------------------------------- //
    var searchInput = document.getElementById('rms-menu-search');
    var countEl     = document.getElementById('rms-search-count');
    var emptyMsg    = document.getElementById('rms-search-empty');
    if (!searchInput) return;

    function applySearch() {
        var query = searchInput.value.trim().toLowerCase();
        var cards = document.querySelectorAll('#rms-simple-grid .rms-card');
        var visibleCount = 0;

        cards.forEach(function (card) {
            var nameEl = card.querySelector('.rms-card-name');
            var name   = nameEl ? nameEl.textContent.trim().toLowerCase() : '';
            var descEl = card.querySelector('.rms-card-desc');
            var desc   = descEl ? descEl.textContent.trim().toLowerCase() : '';
            var matchesSearch = !query || name.indexOf(query) !== -1 || desc.indexOf(query) !== -1;

            if (matchesSearch) {
                card.classList.remove('rms-search-hidden');
            } else {
                card.classList.add('rms-search-hidden');
            }
            // Visible only if search matches AND the dietary
            // filter (which sets inline display:none) hasn't
            // already hidden it — the two filters combine.
            var isVisible = matchesSearch && card.style.display !== 'none';
            if (isVisible) visibleCount++;
        });

        if (countEl) {
            countEl.textContent = query ? (visibleCount + (visibleCount === 1 ? ' dish' : ' dishes')) : '';
        }
        if (emptyMsg) {
            emptyMsg.classList.toggle('d-none', visibleCount !== 0);
        }
    }

    searchInput.addEventListener('input', applySearch);

    // Re-apply search after the dietary filter button runs (it
    // rewrites card.style.display), so the two filters combine
    // instead of one undoing the other.
    document.addEventListener('click', function (e) {
        if (e.target.closest('.rms-diet-btn')) {
            setTimeout(applySearch, 0);
        }
    });
})();

(function () {
    var dateInput = document.getElementById('res_date');
    var timeInput = document.getElementById('res_time');
    var endTimeInput = document.getElementById('res_end_time');
    var timeNote  = document.getElementById('res_time_note');
    var HOURS = JSON.parse((timeNote && timeNote.dataset.hours) || '{}');

    function previousQuarterHour(value) {
        var parts = value.split(':').map(Number);
        var minutes = parts[0] * 60 + parts[1] - 15;
        return String(Math.floor(minutes / 60)).padStart(2, '0') + ':' +
               String(minutes % 60).padStart(2, '0');
    }

    if (dateInput && timeInput) {
        function applyHoursForDate() {
            var d   = new Date(dateInput.value + 'T00:00:00');
            var day = d.getDay(); // JS: 0=Sun, 1=Mon, ..., 6=Sat
            // Remap JS day to our HOURS keys (Mon=0 ... Sun=6)
            var remap = { 0:6, 1:0, 2:1, 3:2, 4:3, 5:4, 6:5 };
            var h = HOURS[remap[day]];
            if (!h) {
                timeInput.value    = '';
                timeInput.min      = '';
                timeInput.max      = '';
                timeInput.disabled = true;
                if (endTimeInput) {
                    endTimeInput.value = '';
                    endTimeInput.min = '';
                    endTimeInput.max = '';
                    endTimeInput.disabled = true;
                }
                timeNote.textContent = 'We are closed on the selected day.';
            } else {
                timeInput.disabled   = false;
                timeInput.min        = h[0];
                timeInput.max        = previousQuarterHour(h[1]);
                if (endTimeInput) {
                    endTimeInput.disabled = false;
                    endTimeInput.min = h[0];
                    endTimeInput.max = h[1];
                }
                timeNote.textContent = 'Open ' + h[0] + ' – ' + h[1];
                // Clear value if outside new range
                if (timeInput.value && (timeInput.value < h[0] || timeInput.value >= h[1])) {
                    timeInput.value = '';
                }
                if (endTimeInput && endTimeInput.value &&
                        (endTimeInput.value <= timeInput.value || endTimeInput.value > h[1])) {
                    endTimeInput.value = '';
                }
            }
        }
        dateInput.addEventListener('change', applyHoursForDate);
        timeInput.addEventListener('change', function () {
            if (endTimeInput) endTimeInput.min = timeInput.value || timeInput.min;
            applyHoursForDate();
        });
        if (dateInput.value) applyHoursForDate();
    }
})();

(function () {
    var whenCard   = document.getElementById('co-when-card');
    var pickupWrap = document.getElementById('co-pickup-wrap');
    var addrWrap   = document.getElementById('co-addr-wrap');
    var addrField  = document.getElementById('co-addr');
    var schedWrap  = document.getElementById('co-sched-wrap');
    var schedDate  = document.getElementById('co-sched-date');
    var schedTime  = document.getElementById('co-sched-time');
    var customTipWrap = document.getElementById('co-custom-tip-wrap');
    var customTip = document.getElementById('co-custom-tip');

    document.querySelectorAll('input[name="tip_choice"]').forEach(function(radio) {
        radio.addEventListener('change', function() {
            var isCustom = this.value === 'custom';
            customTipWrap.style.display = isCustom ? 'flex' : 'none';
            customTip.required = isCustom;
            if (!isCustom) customTip.value = '';
        });
    });

    // Address sub-fields (combined into addrField before submit)
    var addrStreet  = document.getElementById('co-addr-street');
    var addrApt     = document.getElementById('co-addr-apt');
    var addrCity    = document.getElementById('co-addr-city');
    var addrZip     = document.getElementById('co-addr-zip');
    var addrState   = document.getElementById('co-addr-state');
    var addrCountry = document.getElementById('co-addr-country');

    // Parse slot data embedded in the page
    var slotData = [];
    try {
        slotData = JSON.parse(document.getElementById('co-sched-data').textContent);
    } catch(e) {}

    // Combine street/apt/city/zip into the single hidden field
    // submitted to the server — keeps the controller unchanged
    // and still gives one clean string for the map/geocoder.
    function combineAddress() {
        var parts   = [];
        var street  = addrStreet.value.trim();
        var apt     = addrApt.value.trim();
        var city    = addrCity.value.trim();
        var zip     = addrZip.value.trim();
        var state   = addrState.value;
        var country = addrCountry.value;
        if (street) parts.push(apt ? (street + ', ' + apt) : street);
        if (city)   parts.push(city);
        if (state)  parts.push(state);
        if (zip)    parts.push(zip);
        if (country) parts.push(country);
        addrField.value = parts.join(', ');
    }
    [addrStreet, addrApt, addrCity, addrZip, addrState].forEach(function(el) {
        el.addEventListener('input', combineAddress);
        el.addEventListener('change', combineAddress);
    });
    combineAddress();   // pre-fill hidden field with State/Country defaults on load

    // Show schedule card when pickup or delivery is chosen
    document.querySelectorAll('input[name="delivery_type"]').forEach(function(r) {
        r.addEventListener('change', function() {
            var isDelivery = this.value === 'delivery';
            var isPickup   = this.value === 'pickup';
            addrWrap.style.display   = isDelivery ? 'block' : 'none';
            pickupWrap.style.display = isPickup   ? 'block' : 'none';
            addrStreet.required      = isDelivery;
            addrCity.required        = isDelivery;
            addrZip.required         = isDelivery;
            var pickupName  = document.getElementById('co-pickup-name');
            var pickupPhone = document.getElementById('co-pickup-phone');
            var pickupEmail = document.getElementById('co-pickup-email');
            if (pickupName)  pickupName.required  = isPickup;
            if (pickupPhone) pickupPhone.required = isPickup;
            if (pickupEmail) pickupEmail.required = false; // always optional
            var addrName  = document.getElementById('co-addr-name');
            var addrPhone = document.getElementById('co-addr-phone');
            var addrEmail = document.getElementById('co-addr-email');
            if (addrName)  addrName.required  = isDelivery;
            if (addrPhone) addrPhone.required = isDelivery;
            if (addrEmail) addrEmail.required = false; // always optional
            whenCard.style.display   = 'block';
        });
    });

    // Show date+time pickers when Schedule is chosen
    function applyScheduleState(isSched) {
        schedWrap.style.display = isSched ? 'block' : 'none';
        schedDate.required      = isSched;
        schedTime.required      = isSched;
        if (!isSched) {
            schedDate.value = '';
            schedTime.innerHTML = '— choose a date first —';
            schedTime.disabled = true;
        }
    }
    document.querySelectorAll('input[name="schedule_type"]').forEach(function(r) {
        r.addEventListener('change', function() {
            applyScheduleState(this.value === 'schedule');
        });
    });
    // Auto-trigger if Schedule is already checked (off-hours pre-select)
    var preChecked = document.querySelector('#co-sched-later');
    if (preChecked && preChecked.checked) {
        applyScheduleState(true);
    }

    // Populate times when a date is selected
    schedDate.addEventListener('change', function() {
        var chosen = this.value;
        schedTime.innerHTML = '';
        schedTime.disabled  = true;
        if (!chosen) {
            schedTime.innerHTML = '— choose a date first —';
            return;
        }
        var day = slotData.find(function(d) { return d.date === chosen; });
        if (!day || !day.times.length) {
            schedTime.innerHTML = 'No slots available';
            return;
        }
        schedTime.innerHTML = '— choose a time —';
        day.times.forEach(function(t) {
            var opt = document.createElement('option');
            opt.value       = t.v;
            opt.textContent = t.l;
            schedTime.appendChild(opt);
        });
        schedTime.disabled = false;
    });

    // Combine address fields right before the form submits
    // (covers cases like browser autofill that skip 'input' events)
    var coForm = addrField.closest('form');
    if (coForm) {
        coForm.addEventListener('submit', combineAddress);
    }

    // Special request character counter (max 60)
    var specialReq   = document.getElementById('co-special-request');
    var specialCount = document.getElementById('co-special-request-count');
    if (specialReq && specialCount) {
        specialReq.addEventListener('input', function() {
            specialCount.textContent = specialReq.value.length;
        });
    }
})();

document.addEventListener('DOMContentLoaded', function () {
    document.querySelectorAll('.rms-stock-toggle').forEach(function (btn) {
        btn.addEventListener('click', async function () {
            const productId = parseInt(btn.dataset.productId);
            btn.disabled = true;
            btn.textContent = 'Saving…';
            const resp = await fetch('/rms/admin/stock/toggle', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({product_id: productId}),
            });
            const data = await resp.json();
            const row  = document.getElementById('row-' + productId);
            const badge = row.querySelector('.badge');
            if (data.available) {
                row.className   = '';
                badge.className = 'badge bg-success';
                badge.textContent = 'Available';
                btn.className   = 'btn btn-sm rms-stock-toggle btn-outline-danger';
                btn.textContent = 'Mark Out of Stock';
            } else {
                row.className   = 'table-secondary text-muted';
                badge.className = 'badge bg-danger';
                badge.textContent = 'Out of Stock';
                btn.className   = 'btn btn-sm rms-stock-toggle btn-outline-success';
                btn.textContent = 'Mark Available';
            }
            btn.disabled = false;
            btn.dataset.available = data.available ? '1' : '0';
        });
    });

    // ---------------------------------------------- //
    // Edit Item modal — one form for everything      //
    // ---------------------------------------------- //
    const editBackdrop  = document.getElementById('rms-edit-item-backdrop');
    const editClose     = document.getElementById('rms-edit-item-close');
    const editCancel    = document.getElementById('rms-edit-item-cancel');
    const editSave      = document.getElementById('rms-edit-item-save');
    const editError     = document.getElementById('rms-edit-item-error');
    const editImageIn   = document.getElementById('rms-edit-image');
    const editImagePrev = document.getElementById('rms-edit-image-preview');
    let   editImageBase64 = '';

    function closeEditModal() {
        editBackdrop.classList.add('d-none');
        editImageIn.value = '';
        editImageBase64 = '';
        editError.classList.add('d-none');
    }

    document.querySelectorAll('.rms-edit-item-btn').forEach(function (btn) {
        btn.addEventListener('click', function () {
            document.getElementById('rms-edit-product-id').value      = btn.dataset.productId;
            document.getElementById('rms-edit-name').value            = btn.dataset.name || '';
            document.getElementById('rms-edit-price').value           = btn.dataset.price || '';
            document.getElementById('rms-edit-description').value     = btn.dataset.description || '';
            document.getElementById('rms-edit-category').value        = btn.dataset.category || '';
            document.getElementById('rms-edit-vegetarian').checked    = btn.dataset.isVegetarian === '1';
            document.getElementById('rms-edit-vegan').checked         = btn.dataset.isVegan === '1';
            document.getElementById('rms-edit-gluten-free').checked   = btn.dataset.isGlutenFree === '1';
            document.getElementById('rms-edit-nuts').checked          = btn.dataset.containsNuts === '1';
            editImagePrev.src = btn.dataset.imageUrl || '';
            editImageIn.value = '';
            editImageBase64 = '';
            editError.classList.add('d-none');
            editBackdrop.classList.remove('d-none');
        });
    });

    if (editClose)  editClose.addEventListener('click', closeEditModal);
    if (editCancel) editCancel.addEventListener('click', closeEditModal);
    if (editBackdrop) {
        editBackdrop.addEventListener('click', function (e) {
            if (e.target === editBackdrop) closeEditModal();
        });
    }

    if (editImageIn) {
        editImageIn.addEventListener('change', function () {
            const file = editImageIn.files[0];
            if (!file) return;
            if (file.size > 8 * 1024 * 1024) {
                alert('That image is too large — please pick one under 8MB.');
                editImageIn.value = '';
                return;
            }
            const reader = new FileReader();
            reader.onload = function (e) {
                editImageBase64 = e.target.result;
                editImagePrev.src = editImageBase64;
            };
            reader.readAsDataURL(file);
        });
    }

    if (editSave) {
        editSave.addEventListener('click', async function () {
            const productId = document.getElementById('rms-edit-product-id').value;
            const name  = document.getElementById('rms-edit-name').value.trim();
            const price = parseFloat(document.getElementById('rms-edit-price').value);

            if (!name) {
                editError.textContent = 'Item name is required.';
                editError.classList.remove('d-none');
                return;
            }
            if (isNaN(price) || price < 0) {
                editError.textContent = 'Please enter a valid price.';
                editError.classList.remove('d-none');
                return;
            }

            editError.classList.add('d-none');
            editSave.disabled = true;
            editSave.textContent = 'Saving…';

            try {
                const resp = await fetch('/rms/admin/stock/update', {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({
                        product_id:      parseInt(productId),
                        name:            name,
                        price:           price,
                        description:     document.getElementById('rms-edit-description').value.trim(),
                        category:        document.getElementById('rms-edit-category').value,
                        is_vegetarian:   document.getElementById('rms-edit-vegetarian').checked,
                        is_vegan:        document.getElementById('rms-edit-vegan').checked,
                        is_gluten_free:  document.getElementById('rms-edit-gluten-free').checked,
                        contains_nuts:   document.getElementById('rms-edit-nuts').checked,
                        image_base64:    editImageBase64,
                    }),
                });
                const data = await resp.json();
                if (data.error) {
                    editError.textContent = data.error;
                    editError.classList.remove('d-none');
                } else {
                    // Reload so every column (name, category label, price,
                    // thumbnail, and the Edit button's own data-* attributes
                    // used to prefill next time) all stay in sync with the
                    // server — simpler and safer than patching each piece by hand.
                    window.location.reload();
                }
            } catch (err) {
                editError.textContent = 'Something went wrong. Please try again.';
                editError.classList.remove('d-none');
            } finally {
                editSave.disabled = false;
                editSave.textContent = 'Save Changes';
            }
        });
    }

    // ---------------------------------------------- //
    // Delete Item modal                              //
    // ---------------------------------------------- //
    const deleteBackdrop = document.getElementById('rms-delete-item-backdrop');
    const deleteClose    = document.getElementById('rms-delete-item-close');
    const deleteCancel   = document.getElementById('rms-delete-item-cancel');
    const deleteConfirm  = document.getElementById('rms-delete-item-confirm');
    const deleteNameEl   = document.getElementById('rms-delete-item-name');
    let   pendingDeleteId = null;

    function closeDeleteModal() {
        deleteBackdrop.classList.add('d-none');
        pendingDeleteId = null;
    }

    document.querySelectorAll('.rms-delete-item-btn').forEach(function (btn) {
        btn.addEventListener('click', function () {
            pendingDeleteId = btn.dataset.productId;
            deleteNameEl.textContent = btn.dataset.name || 'this item';
            deleteBackdrop.classList.remove('d-none');
        });
    });

    if (deleteClose)  deleteClose.addEventListener('click', closeDeleteModal);
    if (deleteCancel) deleteCancel.addEventListener('click', closeDeleteModal);
    if (deleteBackdrop) {
        deleteBackdrop.addEventListener('click', function (e) {
            if (e.target === deleteBackdrop) closeDeleteModal();
        });
    }

    if (deleteConfirm) {
        deleteConfirm.addEventListener('click', async function () {
            if (!pendingDeleteId) return;
            deleteConfirm.disabled = true;
            deleteConfirm.textContent = 'Deleting…';
            try {
                const resp = await fetch('/rms/admin/stock/delete', {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({product_id: parseInt(pendingDeleteId)}),
                });
                const data = await resp.json();
                if (data.error) {
                    alert('Could not delete: ' + data.error);
                    deleteConfirm.disabled = false;
                    deleteConfirm.textContent = 'Delete';
                } else {
                    const row = document.getElementById('row-' + pendingDeleteId);
                    if (row) row.remove();
                    closeDeleteModal();
                    deleteConfirm.disabled = false;
                    deleteConfirm.textContent = 'Delete';
                }
            } catch (err) {
                alert('Something went wrong. Please try again.');
                deleteConfirm.disabled = false;
                deleteConfirm.textContent = 'Delete';
            }
        });
    }

    // ---------------------------------------------- //
    // Add New Item modal                            //
    // ---------------------------------------------- //
    const addBackdrop   = document.getElementById('rms-add-item-backdrop');
    const addBtn        = document.getElementById('rms-add-item-btn');
    const closeBtn      = document.getElementById('rms-add-item-close');
    const cancelBtn     = document.getElementById('rms-add-item-cancel');
    const saveBtn       = document.getElementById('rms-add-item-save');
    const errorBox      = document.getElementById('rms-add-item-error');
    const imageInput    = document.getElementById('rms-new-image');
    const imagePreview  = document.getElementById('rms-new-image-preview');
    let   newImageBase64 = '';

    function openModal() {
        errorBox.classList.add('d-none');
        addBackdrop.classList.remove('d-none');
    }
    function closeModal() {
        addBackdrop.classList.add('d-none');
        document.getElementById('rms-new-name').value = '';
        document.getElementById('rms-new-description').value = '';
        document.getElementById('rms-new-price').value = '';
        document.getElementById('rms-new-category').value = '';
        document.getElementById('rms-new-vegetarian').checked = false;
        document.getElementById('rms-new-vegan').checked = false;
        document.getElementById('rms-new-gluten-free').checked = false;
        document.getElementById('rms-new-nuts').checked = false;
        imageInput.value = '';
        imagePreview.classList.add('d-none');
        newImageBase64 = '';
    }

    if (addBtn)    addBtn.addEventListener('click', openModal);
    if (closeBtn)  closeBtn.addEventListener('click', closeModal);
    if (cancelBtn) cancelBtn.addEventListener('click', closeModal);
    if (addBackdrop) {
        addBackdrop.addEventListener('click', function (e) {
            if (e.target === addBackdrop) closeModal();
        });
    }

    if (imageInput) {
        imageInput.addEventListener('change', function () {
            const file = imageInput.files[0];
            if (!file) return;
            const reader = new FileReader();
            reader.onload = function (e) {
                newImageBase64 = e.target.result;
                imagePreview.src = newImageBase64;
                imagePreview.classList.remove('d-none');
            };
            reader.readAsDataURL(file);
        });
    }

    if (saveBtn) {
        saveBtn.addEventListener('click', async function () {
            const name  = document.getElementById('rms-new-name').value.trim();
            const price = parseFloat(document.getElementById('rms-new-price').value);

            if (!name) {
                errorBox.textContent = 'Item name is required.';
                errorBox.classList.remove('d-none');
                return;
            }
            if (isNaN(price) || price < 0) {
                errorBox.textContent = 'Please enter a valid price.';
                errorBox.classList.remove('d-none');
                return;
            }

            errorBox.classList.add('d-none');
            saveBtn.disabled = true;
            saveBtn.textContent = 'Adding…';

            try {
                const resp = await fetch('/rms/admin/stock/create', {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({
                        name:            name,
                        price:           price,
                        description:     document.getElementById('rms-new-description').value.trim(),
                        category:        document.getElementById('rms-new-category').value,
                        is_vegetarian:   document.getElementById('rms-new-vegetarian').checked,
                        is_vegan:        document.getElementById('rms-new-vegan').checked,
                        is_gluten_free:  document.getElementById('rms-new-gluten-free').checked,
                        contains_nuts:   document.getElementById('rms-new-nuts').checked,
                        image_base64:    newImageBase64,
                    }),
                });
                const data = await resp.json();
                if (data.error) {
                    errorBox.textContent = data.error;
                    errorBox.classList.remove('d-none');
                } else {
                    // Reload so the new row renders with full server-side
                    // markup (price editing, toggle button, etc.) — simpler
                    // and more reliable than hand-building the table row in JS.
                    window.location.reload();
                }
            } catch (err) {
                errorBox.textContent = 'Something went wrong. Please try again.';
                errorBox.classList.remove('d-none');
            } finally {
                saveBtn.disabled = false;
                saveBtn.textContent = 'Add Item';
            }
        });
    }
});

(function() {
    function setFilterTop() {
        var hdr  = document.querySelector('header#top, .o_header_standard, nav.navbar');
        var h    = hdr ? hdr.offsetHeight : 0;
        var cat  = document.querySelector('.rms-cat-mobile');
        if (cat) cat.style.top = h + 'px';
    }
    window.addEventListener('load',   setFilterTop);
    window.addEventListener('resize', setFilterTop);
    setFilterTop();
})();
